/**
 * @fileoverview Shared floating/dropdown positioning utility.
 *
 * Consolidates the duplicated dropdown-positioning logic found in
 * Combobox, DynamicSearch, DatePicker, HintBox, and ClipBox into a
 * single reusable function.
 *
 * @module shared/positionFloating
 */

import { DROPDOWN_GAP_PX, VIEWPORT_MARGIN_PX } from './tokens/layout.js';

// ── Defaults ─────────────────────────────────

/** @type {import('./positionFloating.js').PositionOptions} */
const OPTION_DEFAULTS = {
    strategy:       'fixed',
    gap:            DROPDOWN_GAP_PX,
    flip:           true,
    viewportMargin: VIEWPORT_MARGIN_PX,
    width:          'match',
};

// ── Core positioning ─────────────────────────

/**
 * Position a floating element relative to an anchor element.
 *
 * Works with both `position: absolute` (adds scroll offsets) and
 * `position: fixed` (viewport-relative). Supports vertical flip
 * (above/below), horizontal overflow clamping, and multiple width
 * strategies.
 *
 * @param {HTMLElement} floatingEl  — the dropdown / popup to position
 * @param {HTMLElement} anchorEl    — the trigger / container element
 * @param {Partial<PositionOptions>} [opts={}]
 * @returns {PositionResult}
 *
 * @typedef {Object} PositionOptions
 * @property {'absolute'|'fixed'} [strategy='fixed']
 *     CSS positioning mode. `'absolute'` adds `scrollX`/`scrollY` offsets;
 *     `'fixed'` uses raw viewport coords.
 * @property {number} [gap=DROPDOWN_GAP_PX]
 *     Vertical gap in px between anchor and floating element.
 * @property {boolean} [flip=true]
 *     Whether to flip above when there isn't enough space below.
 * @property {number} [viewportMargin=VIEWPORT_MARGIN_PX]
 *     Minimum px distance from the right edge of the viewport.
 * @property {'match'|'min-match'|'auto'} [width='match']
 *     `'match'`     → set `width` to anchor width.
 *     `'min-match'` → set `min-width` to anchor width, `width: auto`.
 *     `'auto'`      → don't touch width at all.
 * @property {number} [minWidth]
 *     Optional minimum width in px (only used with `'min-match'`).
 *
 * @typedef {Object} PositionResult
 * @property {boolean} flipped — `true` when the dropdown was placed above.
 * @property {number}  top     — computed CSS `top` in px.
 * @property {number}  left    — computed CSS `left` in px.
 * @property {string}  strategy — the strategy that was applied.
 */
export function positionFloating(floatingEl, anchorEl, opts = {}) {
    const o = { ...OPTION_DEFAULTS, ...opts };

    const isAbsolute = o.strategy === 'absolute';

    // Measure anchor
    const anchorRect = anchorEl.getBoundingClientRect();

    // Ensure the floating element is measurable
    floatingEl.style.position = o.strategy;
    floatingEl.style.display  = '';

    // ── Width ────────────────────────────────
    if (o.width === 'match') {
        floatingEl.style.width    = anchorRect.width + 'px';
        floatingEl.style.minWidth = '';
    } else if (o.width === 'min-match') {
        const minW = o.minWidth
            ? Math.max(o.minWidth, anchorRect.width)
            : anchorRect.width;
        floatingEl.style.minWidth = minW + 'px';
        floatingEl.style.width    = 'auto';
    }
    // 'auto' → leave width untouched

    // ── Vertical flip ────────────────────────
    const floatingH    = floatingEl.offsetHeight;
    const spaceBelow   = window.innerHeight - anchorRect.bottom;
    const spaceAbove   = anchorRect.top;
    const flipped      = o.flip
        ? (spaceBelow < floatingH + o.gap && spaceAbove > spaceBelow)
        : false;

    // ── Scroll offsets (only for absolute) ───
    const scrollX = isAbsolute ? window.scrollX : 0;
    const scrollY = isAbsolute ? window.scrollY : 0;

    // ── Vertical coordinate ──────────────────
    const top = flipped
        ? anchorRect.top  + scrollY - floatingH - o.gap
        : anchorRect.bottom + scrollY + o.gap;

    // ── Horizontal coordinate + clamping ─────
    const floatingW     = floatingEl.offsetWidth;
    const viewportRight = window.innerWidth + scrollX;
    let left            = anchorRect.left + scrollX;

    if (left + floatingW > viewportRight) {
        // Align dropdown's right edge with anchor's right edge
        left = anchorRect.right + scrollX - floatingW;
        // Ensure it doesn't go off-screen to the left
        if (left < o.viewportMargin) left = o.viewportMargin;
    }

    // ── Apply styles ─────────────────────────
    floatingEl.style.left = left + 'px';
    floatingEl.style.top  = top  + 'px';

    return { flipped, top, left, strategy: o.strategy };
}
